import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace } from "@tigrisdata/agent-kit";
import { put } from "@tigrisdata/storage";

async function main() {
  let trialId: string;
  try {
    trialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();
  } catch (err) {
    console.error("Failed to read trial_id:", err);
    process.exit(1);
    return;
  }

  const workspaceName = `harbor-ws-${trialId}`
    .toLowerCase()
    .replace(/[^a-z0-9.-]/g, "-");

  const workspaceResult = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    credentials: { role: "Editor" },
  });

  if (workspaceResult.error) {
    console.error("Error creating workspace:", workspaceResult.error);
    process.exit(1);
    return;
  }

  const workspace = workspaceResult.data;
  if (!workspace || !workspace.credentials) {
    console.error("Workspace or credentials missing in response");
    process.exit(1);
    return;
  }

  const { bucket, credentials } = workspace;
  const { accessKeyId, secretAccessKey } = credentials;

  const body = JSON.stringify({ status: "ok", run: trialId });

  const putResult = await put({
    bucket,
    key: "state.json",
    body,
    contentType: "application/json",
    config: {
      bucket,
      accessKeyId,
      secretAccessKey,
    },
  });

  if (putResult.error) {
    console.error("Error uploading object:", putResult.error);
    process.exit(1);
    return;
  }

  process.stdout.write(accessKeyId + "\n");
  await writeFile("/home/user/tigris-task/output.log", accessKeyId);
}

main().catch((err) => {
  console.error("Unhandled error:", err);
  process.exit(1);
});

